    // Execute the transaction
    const txHash = await preparedSendRequest.execute();
    // Wait for transaction confirmation (2 confirmations)
    const receipt = await fromAdapter.waitForTransaction(txHash, {
        confirmations: 2
    }, fromChain);
    // Build the explorer URL
    const explorerUrl = buildExplorerUrl(fromChain, txHash);
